  1→package git
  2→
  3→import (
  4→	"encoding/json"
  5→	"entire-dashboard/models"
  6→	"fmt"
  7→	"os/exec"
  8→	"strconv"
  9→	"strings"
 10→)
 11→
 12→const shadowBranch = "entire/checkpoints/v1"
 13→
 14→// Reader reads Entire checkpoint data from a git repository's shadow branch.
 15→type Reader struct {
 16→	repoPath string
 17→}
 18→
 19→func NewReader(repoPath string) *Reader {
 20→	return &Reader{repoPath: repoPath}
 21→}
 22→
 23→// ReadAllSessions extracts all session metadata from the shadow branch.
 24→func (r *Reader) ReadAllSessions() ([]models.Session, error) {
 25→	// List top-level directories (2-char prefixes)
 26→	prefixes, err := r.lsTree(shadowBranch)
 27→	if err != nil {
 28→		return nil, fmt.Errorf("list prefixes: %w", err)
 29→	}
 30→
 31→	var sessions []models.Session
 32→	for _, prefix := range prefixes {
 33→		// List checkpoint IDs under each prefix
 34→		checkpointIDs, err := r.lsTree(shadowBranch + ":" + prefix + "/")
 35→		if err != nil {
 36→			continue
 37→		}
 38→		for _, cpID := range checkpointIDs {
 39→			path := prefix + "/" + cpID
 40→			ss, err := r.readCheckpointSessions(path, prefix+cpID)
 41→			if err != nil {
 42→				continue
 43→			}
 44→			sessions = append(sessions, ss...)
 45→		}
 46→	}
 47→	return sessions, nil
 48→}
 49→
 50→func (r *Reader) readCheckpointSessions(treePath, checkpointID string) ([]models.Session, error) {
 51→	// List entries in this checkpoint (numbered session dirs + metadata.json)
 52→	entries, err := r.lsTree(shadowBranch + ":" + treePath + "/")
 53→	if err != nil {
 54→		return nil, err
 55→	}
 56→
 57→	var sessions []models.Session
 58→	for _, entry := range entries {
 59→		// Only process numbered directories (session indices)
 60→		if _, err := strconv.Atoi(entry); err != nil {
 61→			continue
 62→		}
 63→
 64→		metaPath := treePath + "/" + entry + "/metadata.json"
 65→		meta, err := r.readSessionMeta(metaPath)
 66→		if err != nil {
 67→			continue
 68→		}
 69→
 70→		prompt := r.readFileContent(treePath + "/" + entry + "/prompt.txt")
 71→
 72→		sessions = append(sessions, models.Session{
 73→			CheckpointID:    meta.CheckpointID,
 74→			SessionID:       meta.SessionID,
 75→			Agent:           meta.Agent,
 76→			Branch:          meta.Branch,
 77→			CreatedAt:       meta.CreatedAt,
 78→			Prompt:          truncate(prompt, 500),
 79→			AgentLines:      meta.Attribution.AgentLines,
 80→			HumanAdded:      meta.Attribution.HumanAdded,
 81→			HumanModified:   meta.Attribution.HumanModified,
 82→			HumanRemoved:    meta.Attribution.HumanRemoved,
 83→			TotalCommitted:  meta.Attribution.TotalCommitted,
 84→			AgentPercentage: meta.Attribution.AgentPercentage,
 85→			InputTokens:     meta.TokenUsage.InputTokens,
 86→			OutputTokens:    meta.TokenUsage.OutputTokens,
 87→			APICallCount:    meta.TokenUsage.APICallCount,
 88→		})
 89→	}
 90→	return sessions, nil
 91→}
 92→
 93→func (r *Reader) readSessionMeta(path string) (models.SessionMeta, error) {
 94→	var meta models.SessionMeta
 95→	content := r.readFileContent(path)
 96→	if content == "" {
 97→		return meta, fmt.Errorf("empty content at %s", path)
 98→	}
 99→	err := json.Unmarshal([]byte(content), &meta)
100→	return meta, err
101→}
102→
103→func (r *Reader) readFileContent(path string) string {
104→	out, err := r.gitShow(shadowBranch + ":" + path)
105→	if err != nil {
106→		return ""
107→	}
108→	return out
109→}
110→
111→func (r *Reader) lsTree(ref string) ([]string, error) {
112→	out, err := exec.Command("git", "-C", r.repoPath, "ls-tree", "--name-only", ref).Output()
113→	if err != nil {
114→		return nil, err
115→	}
116→	lines := strings.Split(strings.TrimSpace(string(out)), "\n")
117→	var result []string
118→	for _, l := range lines {
119→		l = strings.TrimSpace(l)
120→		if l != "" {
121→			result = append(result, l)
122→		}
123→	}
124→	return result, nil
125→}
126→
127→func (r *Reader) gitShow(ref string) (string, error) {
128→	out, err := exec.Command("git", "-C", r.repoPath, "show", ref).Output()
129→	if err != nil {
130→		return "", err
131→	}
132→	return string(out), nil
133→}
134→
135→func truncate(s string, maxLen int) string {
136→	runes := []rune(s)
137→	if len(runes) <= maxLen {
138→		return s
139→	}
140→	return string(runes[:maxLen]) + "..."
141→}
