 43→		if _, err := store.AddRepo(absRepo, name); err != nil {
 44→			// Ignore duplicate error (already registered)
 45→			log.Printf("repo registration: %v (may already exist)", err)
 46→		}
 47→	}
 48→
 49→	h := handlers.New(store)
 50→
 51→	ogenServer, err := generated.NewServer(h)
 52→	if err != nil {
 53→		log.Fatalf("create ogen server: %v", err)
 54→	}
 55→
 56→	// Resolve frontend static file directory
 57→	var fileServer http.Handler
 58→	frontendDir := filepath.Join(filepath.Dir(os.Args[0]), "..", "frontend", "dist")
 59→	if _, err := os.Stat(frontendDir); err == nil {
 60→		fileServer = http.FileServer(http.Dir(frontendDir))
 61→	} else {
 62→		devFrontend := filepath.Join(".", "..", "frontend", "dist")
 63→		if _, err := os.Stat(devFrontend); err == nil {
 64→			fileServer = http.FileServer(http.Dir(devFrontend))
 65→		}
 66→	}
 67→
 68→	// Route /api/* to ogen, everything else to static files
 69→	root := http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
 70→		if len(r.URL.Path) >= 4 && r.URL.Path[:4] == "/api" {
 71→			ogenServer.ServeHTTP(w, r)
 72→			return
 73→		}
 74→		if fileServer != nil {
 75→			fileServer.ServeHTTP(w, r)
 76→			return
 77→		}
 78→		http.NotFound(w, r)
 79→	})
 80→
 81→	// CORS middleware for development
 82→	handler := corsMiddleware(root)
 83→
 84→	log.Printf("Starting server on :%s", *port)
 85→	log.Fatal(http.ListenAndServe(":"+*port, handler))
 86→}
 87→
 88→func corsMiddleware(next http.Handler) http.Handler {
 89→	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
 90→		w.Header().Set("Access-Control-Allow-Origin", "*")
 91→		w.Header().Set("Access-Control-Allow-Methods", "GET, POST, DELETE, OPTIONS")
 92→		w.Header().Set("Access-Control-Allow-Headers", "Content-Type")
 93→		if r.Method == "OPTIONS" {
 94→			w.WriteHeader(http.StatusOK)
 95→			return
 96→		}
 97→		next.ServeHTTP(w, r)
 98→	})
 99→}
